query:
-- Matches mit ungültiger seasonId
SELECT m.id, m.type, m.seasonId FROM matches m
WHERE NOT EXISTS (SELECT 1 FROM seasons s WHERE s.id = m.seasonId);

-- Doppel/Mixed-Matches ohne player2_id oder player4_id
SELECT m.id, m.type, m.player2_id, m.player4_id FROM matches m
WHERE m.type IN ('doubles', 'mixed') AND (m.player2_id IS NULL OR m.player4_id IS NULL);

-- Mehrere aktive Saisons (sollte max. 1 geben)
SELECT COUNT(*) as active_count FROM seasons WHERE is_active = 1;

